import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { toast } from 'sonner';
import { ShoppingBag, Trash2, ArrowRight } from 'lucide-react';

export default function Cart() {
  const [cart, setCart] = useState(null);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();
  
  const token = localStorage.getItem('token');

  useEffect(() => {
    if (!token) {
      toast.error('Please login to view your cart');
      navigate('/login');
      return;
    }
    fetchCart();
  }, [token, navigate]);

  const fetchCart = async () => {
    try {
      // Mock cart fetch
      await new Promise(r => setTimeout(r, 500));
      setCart({
        items: []
      });
    } catch (err) {
      toast.error('Could not load cart');
    } finally {
      setLoading(false);
    }
  };

  const removeItem = async (productId, variantId) => {
    try {
      const url = `http://localhost:8000/api/cart/items/${productId}${variantId ? `?variant_id=${variantId}` : ''}`;
      const res = await fetch(url, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (!res.ok) throw new Error('Failed to remove item');
      fetchCart();
      toast.success('Item removed');
    } catch (err) {
      toast.error(err.message);
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center min-h-[60vh]">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
      </div>
    );
  }

  const subtotal = cart?.items?.reduce((sum, item) => sum + (item.price_at_addition * item.quantity), 0) || 0;

  return (
    <div className="min-h-screen bg-background pt-24 pb-16">
      <div className="container mx-auto px-4 max-w-5xl">
        <h1 className="text-4xl font-serif text-foreground mb-8">Shopping Bag</h1>
        
        {!cart?.items?.length ? (
          <div className="text-center py-16 bg-card rounded-2xl border border-border/50">
            <ShoppingBag className="mx-auto h-16 w-16 text-muted-foreground mb-4 opacity-50" />
            <h2 className="text-xl font-medium text-foreground mb-2">Your cart is empty</h2>
            <p className="text-muted-foreground mb-8">Looks like you haven't added anything to your cart yet.</p>
            <Link to="/collection" className="inline-flex items-center px-6 py-3 bg-primary text-primary-foreground font-medium rounded-full hover:bg-primary/90 transition-all">
              Continue Shopping
            </Link>
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
            {/* Cart Items */}
            <div className="lg:col-span-2 space-y-6">
              {cart.items.map((item, index) => (
                <div key={index} className="flex gap-6 p-6 bg-card rounded-2xl border border-border/50 hover:shadow-md transition-all">
                  <div className="w-24 h-32 bg-muted rounded-lg flex-shrink-0 animate-pulse">
                     {/* Placeholder for Product Image */}
                  </div>
                  <div className="flex-1 flex flex-col justify-between">
                    <div>
                      <div className="flex justify-between items-start">
                        <h3 className="font-serif text-lg font-medium text-foreground">{item.product_id}</h3>
                        <p className="font-medium">Rp {item.price_at_addition.toLocaleString('id-ID')}</p>
                      </div>
                      <p className="text-sm text-muted-foreground mt-1">Variant: {item.variant_id || 'Standard'}</p>
                    </div>
                    <div className="flex justify-between items-center mt-4">
                      <div className="flex items-center gap-3">
                        <span className="text-sm text-muted-foreground">Qty:</span>
                        <span className="font-medium bg-secondary px-3 py-1 rounded-md">{item.quantity}</span>
                      </div>
                      <button 
                        onClick={() => removeItem(item.product_id, item.variant_id)}
                        className="text-muted-foreground hover:text-destructive transition-colors flex items-center gap-1 text-sm font-medium"
                      >
                        <Trash2 className="w-4 h-4" /> Remove
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {/* Order Summary */}
            <div className="lg:col-span-1">
              <div className="bg-card p-6 rounded-2xl border border-border/50 sticky top-24">
                <h3 className="font-serif text-xl font-medium text-foreground mb-6">Order Summary</h3>
                <div className="space-y-4 text-sm">
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Subtotal</span>
                    <span className="font-medium">Rp {subtotal.toLocaleString('id-ID')}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Shipping</span>
                    <span className="text-muted-foreground">Calculated at checkout</span>
                  </div>
                  <div className="border-t pt-4 flex justify-between items-end">
                    <span className="font-medium text-foreground">Total</span>
                    <span className="text-2xl font-serif text-primary">Rp {subtotal.toLocaleString('id-ID')}</span>
                  </div>
                </div>
                <Link 
                  to="/checkout"
                  className="w-full mt-8 flex items-center justify-center gap-2 bg-foreground text-background py-4 rounded-full font-medium hover:bg-foreground/90 transition-all group"
                >
                  Proceed to Checkout
                  <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                </Link>
                <div className="mt-6 space-y-3">
                  <div className="flex gap-2 text-xs text-muted-foreground justify-center items-center">
                    <span>✓ Secure Checkout</span>
                    <span>•</span>
                    <span>✓ Free returns</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
